# GNU linker version script for libhelm4j.so
# Hides all internal Go symbols, exposing only the 21 CGo-exported functions
# and the minimal CGo/Go-runtime ABI symbols that the dynamic linker requires.
{
    global:
        # ---- Public API (CGo //export annotations) ----
        FreeString;
        HelmDependency;
        HelmGet;
        HelmHistory;
        HelmInstall;
        HelmLint;
        HelmList;
        HelmPackage;
        HelmPull;
        HelmPush;
        HelmRegistry;
        HelmRepo;
        HelmRollback;
        HelmSearch;
        HelmShow;
        HelmStatus;
        HelmTemplate;
        HelmTest;
        HelmUninstall;
        HelmUpgrade;
        HelmVersion;

        # ---- CGo runtime ABI (required by Go's CGo glue code) ----
        # CGo calling-convention helpers looked up via dlsym at load time
        crosscall2;
        # CGo context / stack management
        _cgo_*;
        # CGo thread startup and traceback hooks (x_cgo_thread_start, etc.)
        x_cgo_*;
        # CGo export trampolines generated by cmd/cgo (_cgoexp_<hash>_<func>)
        _cgoexp_*;

    local: *;
};
